('Découvrir Nivra', 'discover-nivra-pro', '🚀 Découvrez pourquoi des milliers de Québécois choisissent Nivra', 'marketing', 
'<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>Découvrir Nivra</title><style>body{margin:0;padding:0;font-family:Arial,Helvetica,sans-serif;background:#f8fafb;-webkit-text-size-adjust:100%}table{border-collapse:collapse}.container{max-width:600px;margin:0 auto;background:#fff;border:1px solid #e5e7eb;border-radius:8px}.header{padding:28px 40px;border-bottom:3px solid #0066CC}h1{margin:0;font-size:26px;font-weight:700;color:#0066CC}.content{padding:40px}.hero{background:linear-gradient(135deg,#0066CC 0%,#004C99 100%);padding:40px;text-align:center;border-radius:8px;margin-bottom:32px}.hero h2{color:#fff;font-size:28px;margin:0 0 12px 0}.hero p{color:rgba(255,255,255,0.9);font-size:16px;margin:0}.feature-box{background:#f8fafb;border:1px solid #e5e7eb;border-radius:8px;padding:24px;margin-bottom:16px}.feature-title{font-size:16px;font-weight:700;color:#1a1a1a;margin:0 0 8px 0}.feature-text{font-size:14px;color:#4a4a4a;margin:0;line-height:1.6}.btn{display:inline-block;background:#0066CC;color:#fff;padding:16px 40px;border-radius:8px;text-decoration:none;font-weight:600;font-size:16px}.footer{padding:32px 40px;background:#1f2937;text-align:center}.footer h4{color:#fff;font-size:18px;margin:0 0 8px 0}.footer p{color:#d1d5db;font-size:13px;margin:0}.footer-links{margin-top:20px}.footer-links a{color:#9ca3af;font-size:12px;text-decoration:none;margin:0 12px}</style></head><body><div style="padding:32px 16px;background:#f8fafb"><table class="container" role="presentation"><tr class="header"><td><table role="presentation" style="width:100%"><tr><td><h1>Nivra Telecom</h1></td><td style="text-align:right;color:#6b7280;font-size:11px;text-transform:uppercase;letter-spacing:1px">Télécommunications</td></tr></table></td></tr><tr><td class="content"><div class="hero"><h2>Le mobile sans compromis</h2><p>Service prépayé professionnel au Québec</p></div><p style="font-size:16px;color:#374151;line-height:1.7;margin:0 0 24px 0">Bonjour {{client_name}},</p><p style="font-size:16px;color:#4a4a4a;line-height:1.7;margin:0 0 32px 0">Vous cherchez un service mobile fiable, sans contrat et à prix juste? Découvrez pourquoi des milliers de Québécois ont fait le choix Nivra.</p><div class="feature-box"><table role="presentation" style="width:100%"><tr><td style="width:50px;vertical-align:top;padding-right:16px"><div style="width:40px;height:40px;background:#e6f0fa;border-radius:50%;text-align:center;line-height:40px;font-size:20px">📋</div></td><td><p class="feature-title">Sans contrat, sans surprise</p><p class="feature-text">Gardez le contrôle total. Changez ou annulez quand vous voulez, sans frais cachés.</p></td></tr></table></div><div class="feature-box"><table role="presentation" style="width:100%"><tr><td style="width:50px;vertical-align:top;padding-right:16px"><div style="width:40px;height:40px;background:#ecfdf5;border-radius:50%;text-align:center;line-height:40px;font-size:20px">💰</div></td><td><p class="feature-title">Prix transparents garantis</p><p class="feature-text">Le prix affiché est le vrai prix. Pas de frais d''activation cachés ni de surprises sur votre facture.</p></td></tr></table></div><div class="feature-box"><table role="presentation" style="width:100%"><tr><td style="width:50px;vertical-align:top;padding-right:16px"><div style="width:40px;height:40px;background:#eff6ff;border-radius:50%;text-align:center;line-height:40px;font-size:20px">🇨🇦</div></td><td><p class="feature-title">Support 100% québécois</p><p class="feature-text">Une équipe locale à votre écoute. Assistance rapide par chat ou ticket, en français.</p></td></tr></table></div><div style="text-align:center;margin:40px 0"><a href="{{cta_link}}" class="btn" style="color:#fff">Voir nos forfaits →</a></div><div style="background:#e6f7f7;border:1px solid #00a3a3;border-radius:8px;padding:20px;text-align:center"><p style="margin:0;color:#007a7a;font-size:14px"><strong>Offre spéciale</strong> — Activation gratuite pour les nouveaux clients ce mois-ci</p></div></td></tr><tr><td class="footer"><h4>Nivra Telecom</h4><p>Fournisseur de services de télécommunications prépayés au Québec</p><div class="footer-links"><a href="https://nivratelecom.ca">Site web</a> | <a href="https://nivratelecom.ca/privacy">Confidentialité</a></div><p style="margin-top:20px;font-size:11px;color:#9ca3af">© 2025 Nivra Communications Inc. | 1799 Av. Pierre-Péladeau, Laval, QC</p></td></tr></table></div></body></html>', 
'["client_name", "cta_link"]', true),

('Proposition personnalisée', 'personalized-proposal-pro', '📊 {{client_name}}, votre proposition sur mesure est prête', 'marketing',
'<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>Proposition personnalisée</title><style>body{margin:0;padding:0;font-family:Arial,Helvetica,sans-serif;background:#f8fafb}table{border-collapse:collapse}.container{max-width:600px;margin:0 auto;background:#fff;border:1px solid #e5e7eb;border-radius:8px}.header{padding:28px 40px;border-bottom:3px solid #0066CC}h1{margin:0;font-size:26px;font-weight:700;color:#0066CC}.content{padding:40px}.proposal-header{background:linear-gradient(135deg,#7c3aed 0%,#6d28d9 100%);padding:32px;text-align:center;border-radius:8px;margin-bottom:32px}.service-row{background:#f8fafb;border:1px solid #e5e7eb;border-radius:8px;padding:16px 20px;margin-bottom:12px}.total-box{background:#f5f3ff;border:2px solid #7c3aed;border-radius:8px;padding:20px;margin-top:24px}.btn{display:inline-block;background:#7c3aed;color:#fff;padding:16px 40px;border-radius:8px;text-decoration:none;font-weight:600;font-size:16px}.footer{padding:32px 40px;background:#1f2937;text-align:center}.footer h4{color:#fff;font-size:18px;margin:0 0 8px 0}.footer p{color:#d1d5db;font-size:13px;margin:0}</style></head><body><div style="padding:32px 16px;background:#f8fafb"><table class="container" role="presentation"><tr class="header"><td><table role="presentation" style="width:100%"><tr><td><h1>Nivra Telecom</h1></td><td style="text-align:right;color:#6b7280;font-size:11px;text-transform:uppercase;letter-spacing:1px">Proposition #{{proposal_id}}</td></tr></table></td></tr><tr><td class="content"><div class="proposal-header"><p style="color:rgba(255,255,255,0.9);font-size:14px;margin:0 0 8px 0;text-transform:uppercase;letter-spacing:1px">Proposition personnalisée</p><h2 style="color:#fff;font-size:24px;margin:0">Préparée pour vous</h2></div><p style="font-size:16px;color:#374151;line-height:1.7">Bonjour {{client_name}},</p><p style="font-size:15px;color:#4a4a4a;line-height:1.7;margin:16px 0 32px 0">Suite à notre échange, je vous ai préparé une proposition adaptée à vos besoins. Voici le détail des services recommandés:</p><h3 style="color:#1a1a1a;font-size:14px;text-transform:uppercase;letter-spacing:0.5px;border-bottom:2px solid #7c3aed;padding-bottom:8px;margin-bottom:16px">Services proposés</h3>{{services_list}}<div class="total-box"><table role="presentation" style="width:100%"><tr><td><p style="color:#6b7280;font-size:13px;text-transform:uppercase;letter-spacing:0.5px;margin:0">Total mensuel estimé</p><p style="color:#4a4a4a;font-size:12px;margin:4px 0 0 0">Taxes en sus</p></td><td style="text-align:right"><span style="color:#7c3aed;font-size:32px;font-weight:700">{{monthly_total}}</span><span style="color:#6b7280;font-size:14px">/mois</span></td></tr></table></div><div style="text-align:center;margin:32px 0"><a href="{{portal_link}}" class="btn" style="color:#fff">Accepter cette proposition →</a></div><div style="background:#f8fafb;border-radius:8px;padding:20px;margin-top:24px"><p style="margin:0 0 8px 0;font-size:14px;color:#374151"><strong>Votre conseiller:</strong> {{agent_name}}</p><p style="margin:0;font-size:13px;color:#6b7280">Cette proposition est valide jusqu''au <strong>{{valid_until}}</strong></p></div></td></tr><tr><td class="footer"><h4>Nivra Telecom</h4><p>1799 Av. Pierre-Péladeau, Laval, QC | Support@nivratelecom.ca</p></td></tr></table></div></body></html>',
'["client_name", "proposal_id", "agent_name", "services_list", "monthly_total", "valid_until", "portal_link"]', true),

('Demande d''avis client', 'feedback-request-pro', '⭐ {{client_name}}, votre avis compte pour nous', 'marketing',
'<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>Demande d''avis</title><style>body{margin:0;padding:0;font-family:Arial,Helvetica,sans-serif;background:#f8fafb}table{border-collapse:collapse}.container{max-width:600px;margin:0 auto;background:#fff;border:1px solid #e5e7eb;border-radius:8px}.header{padding:28px 40px;border-bottom:3px solid #0066CC}h1{margin:0;font-size:26px;font-weight:700;color:#0066CC}.content{padding:40px}.rating-box{background:linear-gradient(135deg,#00a3a3 0%,#007a7a 100%);padding:32px;text-align:center;border-radius:8px;margin:24px 0}.stars{margin:16px 0}.star{display:inline-block;width:48px;height:48px;background:#fff;border-radius:50%;margin:0 6px;text-decoration:none;line-height:48px;font-size:24px}.btn{display:inline-block;background:#00a3a3;color:#fff;padding:16px 40px;border-radius:8px;text-decoration:none;font-weight:600;font-size:16px}.footer{padding:32px 40px;background:#1f2937;text-align:center}.footer h4{color:#fff;font-size:18px;margin:0 0 8px 0}.footer p{color:#d1d5db;font-size:13px;margin:0}</style></head><body><div style="padding:32px 16px;background:#f8fafb"><table class="container" role="presentation"><tr class="header"><td><h1>Nivra Telecom</h1></td></tr><tr><td class="content"><p style="font-size:16px;color:#374151;line-height:1.7">Bonjour {{client_name}},</p><p style="font-size:15px;color:#4a4a4a;line-height:1.7;margin:16px 0">Vous êtes client{{client_since}} et votre satisfaction est notre priorité. Nous aimerions connaître votre expérience avec nos services.</p><div class="rating-box"><p style="color:#fff;font-size:18px;font-weight:600;margin:0 0 8px 0">Comment évaluez-vous Nivra?</p><p style="color:rgba(255,255,255,0.9);font-size:14px;margin:0 0 16px 0">Cliquez sur une étoile</p><div class="stars"><a href="{{feedback_link}}?rating=1" class="star">1⭐</a><a href="{{feedback_link}}?rating=2" class="star">2⭐</a><a href="{{feedback_link}}?rating=3" class="star">3⭐</a><a href="{{feedback_link}}?rating=4" class="star">4⭐</a><a href="{{feedback_link}}?rating=5" class="star">5⭐</a></div></div><p style="font-size:15px;color:#4a4a4a;line-height:1.7;text-align:center">Votre avis nous aide à améliorer constamment nos services pour mieux vous servir.</p><div style="text-align:center;margin:32px 0"><a href="{{feedback_link}}" class="btn" style="color:#fff">Donner mon avis détaillé →</a></div><div style="background:#ecfdf5;border:1px solid #a7f3d0;border-radius:8px;padding:16px;text-align:center"><p style="margin:0;color:#047857;font-size:14px">🎁 <strong>Merci!</strong> Chaque avis reçu nous aide à vous offrir un meilleur service.</p></div></td></tr><tr><td class="footer"><h4>Nivra Telecom</h4><p>Votre opinion est précieuse. Merci de votre confiance!</p></td></tr></table></div></body></html>',
'["client_name", "client_since", "feedback_link"]', true),

('Panier abandonné', 'abandoned-cart-pro', '🛒 {{client_name}}, vous avez oublié quelque chose!', 'marketing',
'<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>Panier abandonné</title><style>body{margin:0;padding:0;font-family:Arial,Helvetica,sans-serif;background:#f8fafb}table{border-collapse:collapse}.container{max-width:600px;margin:0 auto;background:#fff;border:1px solid #e5e7eb;border-radius:8px}.header{padding:28px 40px;border-bottom:3px solid #0066CC}h1{margin:0;font-size:26px;font-weight:700;color:#0066CC}.content{padding:40px}.cart-item{background:#f8fafb;border:1px solid #e5e7eb;border-radius:8px;padding:20px;margin-bottom:12px}.item-name{font-size:16px;font-weight:600;color:#1a1a1a;margin:0}.item-price{font-size:18px;font-weight:700;color:#0066CC}.total-box{background:#e6f0fa;border:2px solid #0066CC;border-radius:8px;padding:20px;margin-top:20px}.btn{display:inline-block;background:#0066CC;color:#fff;padding:16px 40px;border-radius:8px;text-decoration:none;font-weight:600;font-size:16px}.footer{padding:32px 40px;background:#1f2937;text-align:center}.footer h4{color:#fff;font-size:18px;margin:0 0 8px 0}.footer p{color:#d1d5db;font-size:13px;margin:0}</style></head><body><div style="padding:32px 16px;background:#f8fafb"><table class="container" role="presentation"><tr class="header"><td><h1>Nivra Telecom</h1></td></tr><tr><td class="content"><div style="text-align:center;margin-bottom:32px"><div style="width:80px;height:80px;background:#fef3c7;border-radius:50%;margin:0 auto 16px;line-height:80px;font-size:40px">🛒</div><h2 style="color:#1a1a1a;font-size:24px;margin:0">Votre panier vous attend</h2></div><p style="font-size:16px;color:#374151;line-height:1.7">Bonjour {{client_name}},</p><p style="font-size:15px;color:#4a4a4a;line-height:1.7;margin:16px 0 24px 0">Vous avez commencé une commande mais ne l''avez pas finalisée. Voici ce que vous aviez sélectionné:</p><h3 style="color:#1a1a1a;font-size:14px;text-transform:uppercase;letter-spacing:0.5px;border-bottom:2px solid #0066CC;padding-bottom:8px;margin-bottom:16px">Votre sélection</h3>{{cart_items}}<div class="total-box"><table role="presentation" style="width:100%"><tr><td><p style="color:#6b7280;font-size:13px;text-transform:uppercase;margin:0">Total estimé</p></td><td style="text-align:right"><span style="color:#0066CC;font-size:28px;font-weight:700">{{cart_total}}</span></td></tr></table></div><div style="text-align:center;margin:32px 0"><a href="{{cart_link}}" class="btn" style="color:#fff">Finaliser ma commande →</a></div><div style="background:#fffbeb;border:1px solid #fcd34d;border-radius:8px;padding:16px"><p style="margin:0;color:#92400e;font-size:14px"><strong>⏰ Ne tardez pas!</strong> Les prix et la disponibilité peuvent changer.</p></div></td></tr><tr><td class="footer"><h4>Nivra Telecom</h4><p>Des questions? Contactez-nous à Support@nivratelecom.ca</p></td></tr></table></div></body></html>',
'["client_name", "cart_items", "cart_total", "cart_link"]', true),

('Invitation parrainage', 'referral-invite-pro', '🎁 {{referrer_name}} vous invite à rejoindre Nivra', 'marketing',
'<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>Invitation parrainage</title><style>body{margin:0;padding:0;font-family:Arial,Helvetica,sans-serif;background:#f8fafb}table{border-collapse:collapse}.container{max-width:600px;margin:0 auto;background:#fff;border:1px solid #e5e7eb;border-radius:8px}.header{padding:28px 40px;border-bottom:3px solid #0066CC}h1{margin:0;font-size:26px;font-weight:700;color:#0066CC}.content{padding:40px}.invite-box{background:linear-gradient(135deg,#059669 0%,#047857 100%);padding:40px;text-align:center;border-radius:8px;margin:24px 0}.code-box{background:#fff;border-radius:8px;padding:16px 32px;display:inline-block;margin-top:16px}.code{font-size:28px;font-weight:700;color:#059669;letter-spacing:2px}.btn{display:inline-block;background:#059669;color:#fff;padding:16px 40px;border-radius:8px;text-decoration:none;font-weight:600;font-size:16px}.footer{padding:32px 40px;background:#1f2937;text-align:center}.footer h4{color:#fff;font-size:18px;margin:0 0 8px 0}.footer p{color:#d1d5db;font-size:13px;margin:0}</style></head><body><div style="padding:32px 16px;background:#f8fafb"><table class="container" role="presentation"><tr class="header"><td><h1>Nivra Telecom</h1></td></tr><tr><td class="content"><p style="font-size:16px;color:#374151;line-height:1.7">Bonjour,</p><p style="font-size:15px;color:#4a4a4a;line-height:1.7;margin:16px 0">Votre ami(e) <strong>{{referrer_name}}</strong> pense que vous aimerez Nivra Telecom et vous invite à découvrir nos services avec un avantage exclusif.</p><div class="invite-box"><p style="color:rgba(255,255,255,0.9);font-size:14px;text-transform:uppercase;letter-spacing:1px;margin:0 0 8px 0">Votre code parrainage</p><div class="code-box"><span class="code">{{referral_code}}</span></div><p style="color:#fff;font-size:18px;font-weight:600;margin:20px 0 0 0">{{referral_benefit}}</p></div><h3 style="color:#1a1a1a;font-size:14px;text-transform:uppercase;letter-spacing:0.5px;border-bottom:2px solid #059669;padding-bottom:8px;margin:32px 0 16px 0">Pourquoi Nivra?</h3><table role="presentation" style="width:100%;margin-bottom:24px"><tr><td style="padding:12px 16px 12px 0;vertical-align:top;width:32px"><span style="font-size:20px">✓</span></td><td style="padding:12px 0"><p style="margin:0;font-size:15px;color:#374151"><strong>Sans contrat</strong> — Liberté totale, sans engagement</p></td></tr><tr><td style="padding:12px 16px 12px 0;vertical-align:top"><span style="font-size:20px">✓</span></td><td style="padding:12px 0"><p style="margin:0;font-size:15px;color:#374151"><strong>Prix clairs</strong> — Pas de frais cachés ni de surprises</p></td></tr><tr><td style="padding:12px 16px 12px 0;vertical-align:top"><span style="font-size:20px">✓</span></td><td style="padding:12px 0"><p style="margin:0;font-size:15px;color:#374151"><strong>Support local</strong> — Équipe québécoise à votre service</p></td></tr></table><div style="text-align:center;margin:32px 0"><a href="{{signup_link}}" class="btn" style="color:#fff">Profiter de l''offre →</a></div></td></tr><tr><td class="footer"><h4>Nivra Telecom</h4><p>Merci de faire confiance à la recommandation de {{referrer_name}}!</p></td></tr></table></div></body></html>',
'["referrer_name", "referral_code", "referral_benefit", "signup_link"]', true),

