('Offre de bienvenue', 'welcome-offer-pro', '🎉 Bienvenue! {{discount_percent}}% de rabais sur votre premier mois', 'promotions',
'<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>Offre de bienvenue</title><style>body{margin:0;padding:0;font-family:Arial,Helvetica,sans-serif;background:#f8fafb}table{border-collapse:collapse}.container{max-width:600px;margin:0 auto;background:#fff;border:1px solid #e5e7eb;border-radius:8px}.header{padding:28px 40px;border-bottom:3px solid #0066CC}h1{margin:0;font-size:26px;font-weight:700;color:#0066CC}.content{padding:40px}.offer-box{background:linear-gradient(135deg,#0066CC 0%,#004C99 100%);padding:40px;text-align:center;border-radius:8px;margin-bottom:32px}.discount{font-size:72px;font-weight:800;color:#fff;line-height:1}.code-container{background:#fff;border-radius:8px;padding:16px;display:inline-block;margin-top:20px}.code{font-size:24px;font-weight:700;color:#0066CC;letter-spacing:3px}.btn{display:inline-block;background:#0066CC;color:#fff;padding:16px 40px;border-radius:8px;text-decoration:none;font-weight:600;font-size:16px}.footer{padding:32px 40px;background:#1f2937;text-align:center}.footer h4{color:#fff;font-size:18px;margin:0 0 8px 0}.footer p{color:#d1d5db;font-size:13px;margin:0}</style></head><body><div style="padding:32px 16px;background:#f8fafb"><table class="container" role="presentation"><tr class="header"><td><h1>Nivra Telecom</h1></td></tr><tr><td class="content"><p style="font-size:16px;color:#374151;line-height:1.7">Bonjour {{client_name}},</p><p style="font-size:15px;color:#4a4a4a;line-height:1.7;margin:16px 0 32px 0">Merci de votre intérêt pour Nivra! Pour vous souhaiter la bienvenue, nous vous offrons une réduction exclusive sur votre première facture.</p><div class="offer-box"><p style="color:rgba(255,255,255,0.9);font-size:14px;text-transform:uppercase;letter-spacing:1px;margin:0 0 12px 0">Offre de bienvenue</p><span class="discount">{{discount_percent}}%</span><p style="color:#fff;font-size:18px;font-weight:500;margin:12px 0 0 0">de rabais sur votre premier mois</p><div class="code-container"><p style="margin:0 0 4px 0;font-size:12px;color:#6b7280;text-transform:uppercase">Votre code promo</p><span class="code">{{promo_code}}</span></div></div><div style="text-align:center;margin:32px 0"><a href="{{cta_link}}" class="btn" style="color:#fff">Activer mon rabais →</a></div><div style="background:#fef3c7;border:1px solid #fcd34d;border-radius:8px;padding:16px;text-align:center"><p style="margin:0;color:#92400e;font-size:14px"><strong>⏰ Offre limitée</strong> — Valide jusqu''au {{expiry_date}}</p></div></td></tr><tr><td class="footer"><h4>Nivra Telecom</h4><p>Le mobile sans compromis, au Québec</p></td></tr></table></div></body></html>',
'["client_name", "discount_percent", "promo_code", "expiry_date", "cta_link"]', true),

('Black Friday', 'black-friday-pro', '⚫ BLACK FRIDAY — Jusqu''à {{discount_percent}}% de rabais!', 'promotions',
'<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>Black Friday</title><style>body{margin:0;padding:0;font-family:Arial,Helvetica,sans-serif;background:#111827}table{border-collapse:collapse}.container{max-width:600px;margin:0 auto;background:#1f2937;border:2px solid #374151;border-radius:8px}.header{padding:28px 40px;border-bottom:2px solid #374151;background:#111827}h1{margin:0;font-size:26px;font-weight:700;color:#fff}.content{padding:40px;background:#1f2937}.hero{background:linear-gradient(135deg,#111827 0%,#1f2937 100%);border:2px solid #fbbf24;padding:48px 32px;text-align:center;border-radius:8px;margin-bottom:32px}.btn{display:inline-block;background:#fbbf24;color:#111827;padding:18px 48px;border-radius:8px;text-decoration:none;font-weight:700;font-size:18px}.footer{padding:32px 40px;background:#111827;text-align:center;border-top:1px solid #374151}.footer h4{color:#fff;font-size:18px;margin:0 0 8px 0}.footer p{color:#9ca3af;font-size:13px;margin:0}</style></head><body><div style="padding:32px 16px;background:#111827"><table class="container" role="presentation"><tr class="header"><td><table role="presentation" style="width:100%"><tr><td><h1>Nivra Telecom</h1></td><td style="text-align:right"><span style="background:#fbbf24;color:#111827;padding:6px 12px;border-radius:4px;font-size:11px;font-weight:700;text-transform:uppercase">BLACK FRIDAY</span></td></tr></table></td></tr><tr><td class="content"><div class="hero"><p style="color:#fbbf24;font-size:14px;text-transform:uppercase;letter-spacing:2px;margin:0 0 16px 0">⚫ Offre exclusive Black Friday ⚫</p><p style="color:#fff;font-size:64px;font-weight:800;margin:0;line-height:1">-{{discount_percent}}%</p><p style="color:#d1d5db;font-size:18px;margin:16px 0 0 0">{{campaign_subtitle}}</p></div><p style="font-size:16px;color:#d1d5db;line-height:1.7;margin:0 0 24px 0">Bonjour {{client_name}},</p><p style="font-size:15px;color:#9ca3af;line-height:1.7;margin:0 0 32px 0">Le Black Friday Nivra est enfin là! Profitez de notre plus grande vente de l''année sur tous nos forfaits et services.</p>{{deals_list}}<div style="background:#374151;border-radius:8px;padding:20px;margin:24px 0;text-align:center"><p style="margin:0 0 8px 0;font-size:12px;color:#9ca3af;text-transform:uppercase">Code promo</p><p style="margin:0;font-size:28px;font-weight:700;color:#fbbf24;letter-spacing:3px">{{promo_code}}</p></div><div style="text-align:center;margin:32px 0"><a href="{{cta_link}}" class="btn">Profiter de l''offre →</a></div><div style="background:#7f1d1d;border:1px solid #dc2626;border-radius:8px;padding:16px;text-align:center"><p style="margin:0;color:#fecaca;font-size:14px"><strong>🔥 DERNIÈRE CHANCE</strong> — Se termine le {{expiry_date}} à minuit!</p></div></td></tr><tr><td class="footer"><h4>Nivra Telecom</h4><p>Le mobile sans compromis | nivratelecom.ca</p></td></tr></table></div></body></html>',
'["client_name", "discount_percent", "campaign_subtitle", "deals_list", "promo_code", "expiry_date", "cta_link"]', true),

('Campagne saisonnière', 'seasonal-campaign-pro', '{{campaign_emoji}} {{campaign_title}} — {{offer_summary}}', 'promotions',
'<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>Campagne saisonnière</title><style>body{margin:0;padding:0;font-family:Arial,Helvetica,sans-serif;background:#f8fafb}table{border-collapse:collapse}.container{max-width:600px;margin:0 auto;background:#fff;border:1px solid #e5e7eb;border-radius:8px}.header{padding:28px 40px;border-bottom:3px solid #0066CC}h1{margin:0;font-size:26px;font-weight:700;color:#0066CC}.content{padding:40px}.campaign-hero{background:linear-gradient(135deg,#0066CC 0%,#00a3a3 100%);padding:48px 32px;text-align:center;border-radius:8px;margin-bottom:32px}.offer-card{background:#f8fafb;border:2px solid #e5e7eb;border-radius:8px;padding:24px;margin-bottom:16px;text-align:center}.btn{display:inline-block;background:#0066CC;color:#fff;padding:16px 40px;border-radius:8px;text-decoration:none;font-weight:600;font-size:16px}.footer{padding:32px 40px;background:#1f2937;text-align:center}.footer h4{color:#fff;font-size:18px;margin:0 0 8px 0}.footer p{color:#d1d5db;font-size:13px;margin:0}</style></head><body><div style="padding:32px 16px;background:#f8fafb"><table class="container" role="presentation"><tr class="header"><td><h1>Nivra Telecom</h1></td></tr><tr><td class="content"><div class="campaign-hero"><p style="font-size:48px;margin:0 0 16px 0">{{campaign_emoji}}</p><h2 style="color:#fff;font-size:28px;margin:0 0 8px 0">{{campaign_title}}</h2><p style="color:rgba(255,255,255,0.9);font-size:16px;margin:0">{{campaign_subtitle}}</p></div><p style="font-size:16px;color:#374151;line-height:1.7">Bonjour {{client_name}},</p><p style="font-size:15px;color:#4a4a4a;line-height:1.7;margin:16px 0 32px 0">{{campaign_message}}</p><div class="offer-card"><p style="color:#6b7280;font-size:13px;text-transform:uppercase;letter-spacing:1px;margin:0 0 8px 0">Offre spéciale</p><p style="color:#0066CC;font-size:32px;font-weight:700;margin:0 0 12px 0">{{offer_summary}}</p><p style="color:#4a4a4a;font-size:14px;margin:0">Code: <strong style="color:#0066CC">{{promo_code}}</strong></p></div><div style="text-align:center;margin:32px 0"><a href="{{cta_link}}" class="btn" style="color:#fff">{{cta_text}} →</a></div><div style="background:#fffbeb;border:1px solid #fcd34d;border-radius:8px;padding:16px;text-align:center"><p style="margin:0;color:#92400e;font-size:14px"><strong>⏰ Offre limitée</strong> — Valide jusqu''au {{expiry_date}}</p></div></td></tr><tr><td class="footer"><h4>Nivra Telecom</h4><p>Le mobile sans compromis</p></td></tr></table></div></body></html>',
'["client_name", "campaign_emoji", "campaign_title", "campaign_subtitle", "campaign_message", "offer_summary", "promo_code", "expiry_date", "cta_text", "cta_link"]', true),

