('Bienvenue nouveau client', 'welcome-new-client-pro', '🎉 Bienvenue chez Nivra, {{client_name}}!', 'onboarding',
'<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>Bienvenue</title><style>body{margin:0;padding:0;font-family:Arial,Helvetica,sans-serif;background:#f8fafb}table{border-collapse:collapse}.container{max-width:600px;margin:0 auto;background:#fff;border:1px solid #e5e7eb;border-radius:8px}.header{padding:28px 40px;border-bottom:3px solid #0066CC}h1{margin:0;font-size:26px;font-weight:700;color:#0066CC}.success-banner{padding:24px 40px;background:#ecfdf5;border-bottom:1px solid #a7f3d0}.content{padding:40px}.step-box{background:#f8fafb;border:1px solid #e5e7eb;border-left:4px solid #0066CC;border-radius:0 8px 8px 0;padding:20px;margin-bottom:16px}.step-number{display:inline-block;width:28px;height:28px;background:#0066CC;color:#fff;border-radius:50%;text-align:center;line-height:28px;font-weight:700;font-size:14px;margin-right:12px}.btn{display:inline-block;background:#0066CC;color:#fff;padding:16px 40px;border-radius:8px;text-decoration:none;font-weight:600;font-size:16px}.footer{padding:32px 40px;background:#1f2937;text-align:center}.footer h4{color:#fff;font-size:18px;margin:0 0 8px 0}.footer p{color:#d1d5db;font-size:13px;margin:0}</style></head><body><div style="padding:32px 16px;background:#f8fafb"><table class="container" role="presentation"><tr class="header"><td><h1>Nivra Telecom</h1></td></tr><tr><td class="success-banner"><table role="presentation" style="width:100%"><tr><td style="width:48px;vertical-align:top"><div style="width:40px;height:40px;background:#fff;border-radius:50%;text-align:center;line-height:40px;border:2px solid #a7f3d0"><span style="font-size:20px">✓</span></div></td><td style="padding-left:16px"><h2 style="color:#059669;font-size:18px;font-weight:700;margin:0 0 4px 0">Compte créé avec succès!</h2><p style="color:#4a4a4a;font-size:14px;margin:0">Bienvenue dans la famille Nivra</p></td></tr></table></td></tr><tr><td class="content"><p style="font-size:16px;color:#374151;line-height:1.7">Bonjour {{client_name}},</p><p style="font-size:15px;color:#4a4a4a;line-height:1.7;margin:16px 0 32px 0">Nous sommes ravis de vous accueillir! Votre compte est maintenant actif et vous pouvez commencer à profiter de nos services. Voici comment démarrer:</p><h3 style="color:#1a1a1a;font-size:14px;text-transform:uppercase;letter-spacing:0.5px;border-bottom:2px solid #0066CC;padding-bottom:8px;margin-bottom:20px">Prochaines étapes</h3><div class="step-box"><table role="presentation"><tr><td style="vertical-align:top"><span class="step-number">1</span></td><td><p style="margin:0 0 4px 0;font-size:15px;font-weight:600;color:#1a1a1a">Accédez à votre portail client</p><p style="margin:0;font-size:14px;color:#4a4a4a">Connectez-vous pour gérer vos services et voir vos factures.</p></td></tr></table></div><div class="step-box"><table role="presentation"><tr><td style="vertical-align:top"><span class="step-number">2</span></td><td><p style="margin:0 0 4px 0;font-size:15px;font-weight:600;color:#1a1a1a">Vérifiez votre forfait</p><p style="margin:0;font-size:14px;color:#4a4a4a">Consultez les détails de votre service et les options disponibles.</p></td></tr></table></div><div class="step-box"><table role="presentation"><tr><td style="vertical-align:top"><span class="step-number">3</span></td><td><p style="margin:0 0 4px 0;font-size:15px;font-weight:600;color:#1a1a1a">Configurez le paiement automatique</p><p style="margin:0;font-size:14px;color:#4a4a4a">Économisez 2$ par mois avec le prélèvement automatique.</p></td></tr></table></div><div style="text-align:center;margin:32px 0"><a href="{{portal_link}}" class="btn" style="color:#fff">Accéder à mon portail →</a></div><div style="background:#e6f0fa;border:1px solid #0066CC;border-radius:8px;padding:20px"><p style="margin:0 0 8px 0;font-size:14px;color:#0066CC;font-weight:600">📧 Votre numéro de compte</p><p style="margin:0;font-size:20px;font-weight:700;color:#1a1a1a">{{account_number}}</p><p style="margin:8px 0 0 0;font-size:13px;color:#6b7280">Conservez ce numéro pour vos communications avec le support.</p></div></td></tr><tr><td class="footer"><h4>Nivra Telecom</h4><p>Merci de votre confiance! | Support@nivratelecom.ca</p></td></tr></table></div></body></html>',
'["client_name", "portal_link", "account_number"]', true),

('Service activé', 'service-activated-pro', '✅ {{client_name}}, votre service {{service_name}} est maintenant actif!', 'onboarding',
'<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>Service activé</title><style>body{margin:0;padding:0;font-family:Arial,Helvetica,sans-serif;background:#f8fafb}table{border-collapse:collapse}.container{max-width:600px;margin:0 auto;background:#fff;border:1px solid #e5e7eb;border-radius:8px}.header{padding:28px 40px;border-bottom:3px solid #0066CC}h1{margin:0;font-size:26px;font-weight:700;color:#0066CC}.success-banner{padding:24px 40px;background:#ecfdf5;border-bottom:1px solid #a7f3d0}.content{padding:40px}.info-card{background:#f8fafb;border:1px solid #e5e7eb;border-radius:8px;padding:24px;margin-bottom:20px}.info-row{padding:12px 0;border-bottom:1px solid #e5e7eb}.info-row:last-child{border-bottom:none}.btn{display:inline-block;background:#059669;color:#fff;padding:16px 40px;border-radius:8px;text-decoration:none;font-weight:600;font-size:16px}.footer{padding:32px 40px;background:#1f2937;text-align:center}.footer h4{color:#fff;font-size:18px;margin:0 0 8px 0}.footer p{color:#d1d5db;font-size:13px;margin:0}</style></head><body><div style="padding:32px 16px;background:#f8fafb"><table class="container" role="presentation"><tr class="header"><td><h1>Nivra Telecom</h1></td></tr><tr><td class="success-banner"><table role="presentation" style="width:100%"><tr><td style="width:48px;vertical-align:top"><div style="width:40px;height:40px;background:#fff;border-radius:50%;text-align:center;line-height:40px;border:2px solid #a7f3d0"><span style="font-size:20px">✅</span></div></td><td style="padding-left:16px"><h2 style="color:#059669;font-size:18px;font-weight:700;margin:0 0 4px 0">Service activé!</h2><p style="color:#4a4a4a;font-size:14px;margin:0">Votre service est maintenant opérationnel</p></td></tr></table></td></tr><tr><td class="content"><p style="font-size:16px;color:#374151;line-height:1.7">Bonjour {{client_name}},</p><p style="font-size:15px;color:#4a4a4a;line-height:1.7;margin:16px 0 32px 0">Excellente nouvelle! Votre service <strong>{{service_name}}</strong> a été activé avec succès. Vous pouvez dès maintenant en profiter.</p><div class="info-card"><h3 style="color:#1a1a1a;font-size:14px;text-transform:uppercase;letter-spacing:0.5px;margin:0 0 16px 0;padding-bottom:12px;border-bottom:2px solid #059669">Détails du service</h3><div class="info-row"><table role="presentation" style="width:100%"><tr><td style="color:#6b7280;font-size:14px">Service</td><td style="text-align:right;font-weight:600;color:#1a1a1a;font-size:14px">{{service_name}}</td></tr></table></div><div class="info-row"><table role="presentation" style="width:100%"><tr><td style="color:#6b7280;font-size:14px">Date d''activation</td><td style="text-align:right;font-weight:600;color:#1a1a1a;font-size:14px">{{activation_date}}</td></tr></table></div><div class="info-row"><table role="presentation" style="width:100%"><tr><td style="color:#6b7280;font-size:14px">Montant mensuel</td><td style="text-align:right;font-weight:600;color:#059669;font-size:14px">{{monthly_price}}/mois</td></tr></table></div></div><div style="text-align:center;margin:32px 0"><a href="{{portal_link}}" class="btn" style="color:#fff">Gérer mon service →</a></div><div style="background:#eff6ff;border:1px solid #bfdbfe;border-radius:8px;padding:16px"><p style="margin:0;color:#1e40af;font-size:14px"><strong>💡 Conseil:</strong> Configurez le prélèvement automatique pour économiser 2$ par mois et ne jamais manquer un paiement.</p></div></td></tr><tr><td class="footer"><h4>Nivra Telecom</h4><p>Merci de votre confiance!</p></td></tr></table></div></body></html>',
'["client_name", "service_name", "activation_date", "monthly_price", "portal_link"]', true),

