('Nouvelle facture', 'new-invoice-pro', '📄 {{client_name}}, votre facture #{{invoice_number}} est disponible', 'billing',
'<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>Nouvelle facture</title><style>body{margin:0;padding:0;font-family:Arial,Helvetica,sans-serif;background:#f8fafb}table{border-collapse:collapse}.container{max-width:600px;margin:0 auto;background:#fff;border:1px solid #e5e7eb;border-radius:8px}.header{padding:28px 40px;border-bottom:3px solid #0066CC}h1{margin:0;font-size:26px;font-weight:700;color:#0066CC}.content{padding:40px}.invoice-card{background:#f8fafb;border:1px solid #e5e7eb;border-radius:8px;padding:32px;text-align:center;margin:24px 0}.amount-box{background:#e6f0fa;border:2px solid #0066CC;border-radius:8px;padding:20px;margin-top:24px}.btn{display:inline-block;background:#0066CC;color:#fff;padding:16px 40px;border-radius:8px;text-decoration:none;font-weight:600;font-size:16px}.footer{padding:32px 40px;background:#1f2937;text-align:center}.footer h4{color:#fff;font-size:18px;margin:0 0 8px 0}.footer p{color:#d1d5db;font-size:13px;margin:0}</style></head><body><div style="padding:32px 16px;background:#f8fafb"><table class="container" role="presentation"><tr class="header"><td><table role="presentation" style="width:100%"><tr><td><h1>Nivra Telecom</h1></td><td style="text-align:right;color:#6b7280;font-size:11px;text-transform:uppercase;letter-spacing:1px">Facture</td></tr></table></td></tr><tr><td class="content"><p style="font-size:16px;color:#374151;line-height:1.7">Bonjour {{client_name}},</p><p style="font-size:15px;color:#4a4a4a;line-height:1.7;margin:16px 0">Votre nouvelle facture est maintenant disponible. Voici le résumé:</p><div class="invoice-card"><p style="color:#6b7280;font-size:13px;text-transform:uppercase;letter-spacing:1px;margin:0 0 8px 0">Facture</p><p style="color:#1a1a1a;font-size:24px;font-weight:700;margin:0">#{{invoice_number}}</p></div><div class="amount-box"><table role="presentation" style="width:100%"><tr><td><p style="color:#6b7280;font-size:13px;text-transform:uppercase;letter-spacing:0.5px;margin:0">Montant à payer</p><p style="color:#4a4a4a;font-size:12px;margin:4px 0 0 0">Échéance: {{due_date}}</p></td><td style="text-align:right"><span style="color:#0066CC;font-size:36px;font-weight:700">{{amount}}</span></td></tr></table></div><div style="text-align:center;margin:32px 0"><a href="{{payment_link}}" class="btn" style="color:#fff">Payer maintenant →</a></div><div style="background:#fef3c7;border:1px solid #fcd34d;border-left:4px solid #d97706;border-radius:4px;padding:16px;margin-top:24px"><table role="presentation" style="width:100%"><tr><td style="width:32px;vertical-align:top;padding-right:12px"><span style="font-size:20px">💳</span></td><td><p style="color:#92400e;font-size:14px;font-weight:600;margin:0 0 4px 0">Paiement par Interac</p><p style="color:#92400e;font-size:13px;margin:0;line-height:1.5">Envoyez votre paiement à <strong>Support@nivratelecom.ca</strong> avec votre numéro de facture comme référence.</p></td></tr></table></div></td></tr><tr><td class="footer"><h4>Nivra Telecom</h4><p>1799 Av. Pierre-Péladeau, Laval, QC | Support@nivratelecom.ca</p></td></tr></table></div></body></html>',
'["client_name", "invoice_number", "amount", "due_date", "payment_link"]', true),

('Rappel de paiement', 'payment-reminder-pro', '⚠️ {{client_name}}, rappel: facture #{{invoice_number}} en attente', 'billing',
'<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>Rappel de paiement</title><style>body{margin:0;padding:0;font-family:Arial,Helvetica,sans-serif;background:#f8fafb}table{border-collapse:collapse}.container{max-width:600px;margin:0 auto;background:#fff;border:1px solid #e5e7eb;border-radius:8px}.header{padding:28px 40px;border-bottom:3px solid #0066CC}h1{margin:0;font-size:26px;font-weight:700;color:#0066CC}.warning-banner{padding:24px 40px;background:#fffbeb;border-bottom:1px solid #fcd34d}.content{padding:40px}.amount-box{background:#fffbeb;border:2px solid #d97706;border-radius:8px;padding:20px;margin:24px 0}.btn{display:inline-block;background:#d97706;color:#fff;padding:16px 40px;border-radius:8px;text-decoration:none;font-weight:600;font-size:16px}.footer{padding:32px 40px;background:#1f2937;text-align:center}.footer h4{color:#fff;font-size:18px;margin:0 0 8px 0}.footer p{color:#d1d5db;font-size:13px;margin:0}</style></head><body><div style="padding:32px 16px;background:#f8fafb"><table class="container" role="presentation"><tr class="header"><td><h1>Nivra Telecom</h1></td></tr><tr><td class="warning-banner"><table role="presentation" style="width:100%"><tr><td style="width:48px;vertical-align:top"><div style="width:40px;height:40px;background:#fff;border-radius:50%;text-align:center;line-height:40px;border:2px solid #fcd34d"><span style="font-size:20px">⚠️</span></div></td><td style="padding-left:16px"><h2 style="color:#d97706;font-size:18px;font-weight:700;margin:0 0 4px 0">Rappel de paiement</h2><p style="color:#4a4a4a;font-size:14px;margin:0">Votre facture arrive bientôt à échéance</p></td></tr></table></td></tr><tr><td class="content"><p style="font-size:16px;color:#374151;line-height:1.7">Bonjour {{client_name}},</p><p style="font-size:15px;color:#4a4a4a;line-height:1.7;margin:16px 0">Nous vous rappelons que votre facture <strong>#{{invoice_number}}</strong> est en attente de paiement.</p><div class="amount-box"><table role="presentation" style="width:100%"><tr><td><p style="color:#92400e;font-size:13px;text-transform:uppercase;letter-spacing:0.5px;margin:0">Montant dû</p><p style="color:#92400e;font-size:12px;margin:4px 0 0 0">Échéance: <strong>{{due_date}}</strong></p></td><td style="text-align:right"><span style="color:#d97706;font-size:32px;font-weight:700">{{amount}}</span></td></tr></table></div><div style="text-align:center;margin:32px 0"><a href="{{payment_link}}" class="btn" style="color:#fff">Payer maintenant →</a></div><div style="background:#fef2f2;border:1px solid #fecaca;border-radius:8px;padding:16px"><p style="margin:0;color:#991b1b;font-size:14px"><strong>⚡ Important:</strong> Un paiement en retard peut entraîner une interruption de vos services. Réglez votre facture dès que possible.</p></div></td></tr><tr><td class="footer"><h4>Nivra Telecom</h4><p>Des questions? Contactez-nous à Support@nivratelecom.ca</p></td></tr></table></div></body></html>',
'["client_name", "invoice_number", "amount", "due_date", "payment_link"]', true),

