('Rendez-vous confirmé', 'appointment-confirmed-pro', '📅 {{client_name}}, votre rendez-vous du {{appointment_date}} est confirmé', 'appointments',
'<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>Rendez-vous confirmé</title><style>body{margin:0;padding:0;font-family:Arial,Helvetica,sans-serif;background:#f8fafb}table{border-collapse:collapse}.container{max-width:600px;margin:0 auto;background:#fff;border:1px solid #e5e7eb;border-radius:8px}.header{padding:28px 40px;border-bottom:3px solid #0066CC}h1{margin:0;font-size:26px;font-weight:700;color:#0066CC}.success-banner{padding:24px 40px;background:#ecfdf5;border-bottom:1px solid #a7f3d0}.content{padding:40px}.appointment-card{background:linear-gradient(135deg,#0066CC 0%,#004C99 100%);border-radius:8px;padding:32px;text-align:center;margin:24px 0}.details-card{background:#f8fafb;border:1px solid #e5e7eb;border-radius:8px;padding:24px;margin:24px 0}.detail-row{padding:12px 0;border-bottom:1px solid #e5e7eb}.detail-row:last-child{border-bottom:none}.btn{display:inline-block;background:#0066CC;color:#fff;padding:14px 32px;border-radius:8px;text-decoration:none;font-weight:600;font-size:15px}.footer{padding:32px 40px;background:#1f2937;text-align:center}.footer h4{color:#fff;font-size:18px;margin:0 0 8px 0}.footer p{color:#d1d5db;font-size:13px;margin:0}</style></head><body><div style="padding:32px 16px;background:#f8fafb"><table class="container" role="presentation"><tr class="header"><td><h1>Nivra Telecom</h1></td></tr><tr><td class="success-banner"><table role="presentation" style="width:100%"><tr><td style="width:48px;vertical-align:top"><div style="width:40px;height:40px;background:#fff;border-radius:50%;text-align:center;line-height:40px;border:2px solid #a7f3d0"><span style="font-size:20px">✓</span></div></td><td style="padding-left:16px"><h2 style="color:#059669;font-size:18px;font-weight:700;margin:0 0 4px 0">Rendez-vous confirmé</h2><p style="color:#4a4a4a;font-size:14px;margin:0">Votre rendez-vous a été planifié avec succès</p></td></tr></table></td></tr><tr><td class="content"><p style="font-size:16px;color:#374151;line-height:1.7">Bonjour {{client_name}},</p><p style="font-size:15px;color:#4a4a4a;line-height:1.7;margin:16px 0">Votre rendez-vous pour <strong>{{service_type}}</strong> est confirmé. Voici les détails:</p><div class="appointment-card"><p style="color:rgba(255,255,255,0.9);font-size:14px;text-transform:uppercase;letter-spacing:1px;margin:0 0 8px 0">Date et heure</p><p style="color:#fff;font-size:28px;font-weight:700;margin:0">{{appointment_date}}</p><p style="color:rgba(255,255,255,0.9);font-size:16px;margin:8px 0 0 0">{{appointment_time}}</p></div><div class="details-card"><h3 style="color:#1a1a1a;font-size:14px;text-transform:uppercase;letter-spacing:0.5px;margin:0 0 16px 0;padding-bottom:12px;border-bottom:2px solid #0066CC">Détails du rendez-vous</h3><div class="detail-row"><table role="presentation" style="width:100%"><tr><td style="color:#6b7280;font-size:14px">📋 Service</td><td style="text-align:right;font-weight:600;color:#1a1a1a;font-size:14px">{{service_type}}</td></tr></table></div><div class="detail-row"><table role="presentation" style="width:100%"><tr><td style="color:#6b7280;font-size:14px">📍 Adresse</td><td style="text-align:right;font-weight:600;color:#1a1a1a;font-size:14px">{{service_address}}</td></tr></table></div><div class="detail-row"><table role="presentation" style="width:100%"><tr><td style="color:#6b7280;font-size:14px">👤 Technicien</td><td style="text-align:right;font-weight:600;color:#1a1a1a;font-size:14px">{{technician_name}}</td></tr></table></div></div><div style="text-align:center;margin:32px 0"><a href="{{calendar_link}}" class="btn" style="color:#fff">📅 Ajouter au calendrier</a></div><div style="background:#eff6ff;border:1px solid #bfdbfe;border-radius:8px;padding:16px"><p style="margin:0;color:#1e40af;font-size:14px"><strong>📞 Besoin de modifier?</strong> Contactez-nous au moins 24h à l''avance pour tout changement.</p></div></td></tr><tr><td class="footer"><h4>Nivra Telecom</h4><p>Support@nivratelecom.ca</p></td></tr></table></div></body></html>',
'["client_name", "service_type", "appointment_date", "appointment_time", "service_address", "technician_name", "calendar_link"]', true),

