('Newsletter mensuelle', 'monthly-newsletter-pro', '📰 {{newsletter_title}} — Les nouvelles Nivra de {{month}}', 'newsletter',
'<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>Newsletter</title><style>body{margin:0;padding:0;font-family:Arial,Helvetica,sans-serif;background:#f8fafb}table{border-collapse:collapse}.container{max-width:600px;margin:0 auto;background:#fff;border:1px solid #e5e7eb;border-radius:8px}.header{padding:28px 40px;border-bottom:3px solid #0066CC}h1{margin:0;font-size:26px;font-weight:700;color:#0066CC}.content{padding:40px}.article-card{background:#f8fafb;border:1px solid #e5e7eb;border-radius:8px;padding:24px;margin-bottom:20px}.article-title{font-size:18px;font-weight:700;color:#1a1a1a;margin:0 0 8px 0}.article-excerpt{font-size:14px;color:#4a4a4a;line-height:1.6;margin:0}.btn{display:inline-block;background:#0066CC;color:#fff;padding:12px 24px;border-radius:6px;text-decoration:none;font-weight:600;font-size:14px}.footer{padding:32px 40px;background:#1f2937;text-align:center}.footer h4{color:#fff;font-size:18px;margin:0 0 8px 0}.footer p{color:#d1d5db;font-size:13px;margin:0}</style></head><body><div style="padding:32px 16px;background:#f8fafb"><table class="container" role="presentation"><tr class="header"><td><table role="presentation" style="width:100%"><tr><td><h1>Nivra Telecom</h1></td><td style="text-align:right"><span style="background:#e6f0fa;color:#0066CC;padding:6px 12px;border-radius:4px;font-size:11px;font-weight:600;text-transform:uppercase">Newsletter</span></td></tr></table></td></tr><tr><td class="content"><div style="background:linear-gradient(135deg,#0066CC 0%,#00a3a3 100%);border-radius:8px;padding:48px 32px;text-align:center;margin-bottom:32px"><p style="color:rgba(255,255,255,0.9);font-size:14px;text-transform:uppercase;letter-spacing:1px;margin:0 0 8px 0">{{month}} {{year}}</p><h2 style="color:#fff;font-size:28px;margin:0">{{newsletter_title}}</h2></div><p style="font-size:16px;color:#374151;line-height:1.7">Bonjour {{client_name}},</p><p style="font-size:15px;color:#4a4a4a;line-height:1.7;margin:16px 0 32px 0">{{intro_text}}</p><h3 style="color:#1a1a1a;font-size:14px;text-transform:uppercase;letter-spacing:0.5px;border-bottom:2px solid #0066CC;padding-bottom:8px;margin-bottom:20px">À la une ce mois-ci</h3>{{articles_html}}<div style="text-align:center;margin:32px 0;padding:24px;background:#e6f7f7;border-radius:8px"><p style="margin:0 0 16px 0;font-size:16px;color:#007a7a;font-weight:600">{{cta_title}}</p><a href="{{cta_link}}" class="btn" style="color:#fff;background:#00a3a3">{{cta_text}} →</a></div></td></tr><tr><td class="footer"><h4>Nivra Telecom</h4><p style="margin-bottom:12px">Le mobile sans compromis, au Québec</p><p style="font-size:11px;color:#9ca3af"><a href="{{unsubscribe_link}}" style="color:#9ca3af">Se désabonner</a> | <a href="https://nivratelecom.ca/portal" style="color:#9ca3af">Gérer mes préférences</a></p></td></tr></table></div></body></html>',
'["client_name", "month", "year", "newsletter_title", "intro_text", "articles_html", "cta_title", "cta_text", "cta_link", "unsubscribe_link"]', true);